import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-041 — ISS module pickability and scene graph","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-041.md","filePath":"adr/ADR-041.md"}'),s={name:"adr/ADR-041.md"};function i(n,e,d,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-041-—-iss-module-pickability-and-scene-graph" tabindex="-1">ADR-041 — ISS module pickability and scene graph <a class="header-anchor" href="#adr-041-—-iss-module-pickability-and-scene-graph" aria-label="Permalink to &quot;ADR-041 — ISS module pickability and scene graph&quot;">​</a></h1><blockquote><p>Status · Accepted<br> Date · 2026-05-05<br> Closes · RFC-013 (with ADR-040, ADR-042)<br> TA anchor · §components<br> Related · ADR-040, PRD-010</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-013 OQ-2 asked how to balance pick granularity vs draw calls. PRD-010 / GH-41 require <strong>17 pick targets</strong>: 16 pressurised modules + <strong>Canadarm2</strong>. Truss and solar arrays are scenery in V1.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="hybrid-mesh-split-rfc-option-c-canadarm" tabindex="-1">Hybrid mesh split (RFC Option C + Canadarm) <a class="header-anchor" href="#hybrid-mesh-split-rfc-option-c-canadarm" aria-label="Permalink to &quot;Hybrid mesh split (RFC Option C + Canadarm)&quot;">​</a></h3><ol><li><strong>Pickable:</strong> one <code>THREE.Mesh</code> (or group leaf) per canonical <code>id</code> in <a href="../../static/data/iss-modules.json"><code>iss-modules.json</code></a>, with <code>userData.moduleId === id</code> and <code>userData.issPickable === true</code>.</li><li><strong>Non-pickable:</strong> merged geometry under name <code>truss_merged</code> with <code>userData.issPickable === false</code> — raycaster excludes these meshes from module hits (or filters after intersect).</li></ol><h3 id="highlight" tabindex="-1">Highlight <a class="header-anchor" href="#highlight" aria-label="Permalink to &quot;Highlight&quot;">​</a></h3><p><strong>Emissive pulse</strong> on <code>MeshStandardMaterial</code> for the selected module (no outline pass in V1 — OutlinePass not assumed available on low-end WebGL).</p><h3 id="draw-calls" tabindex="-1">Draw calls <a class="header-anchor" href="#draw-calls" aria-label="Permalink to &quot;Draw calls&quot;">​</a></h3><p>Expect <strong>~18 meshes</strong> (17 pickable + 1 truss) — within mobile budget for static geometry.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Trivial <code>userData.moduleId</code> wiring from raycast → panel.</p><p><strong>Negative:</strong> NASA-derived future imports must preserve naming map or an alias table in code.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Scene traversal after <code>GLTFLoader.load</code>: register pickables in an array for <code>Raycaster.intersectObjects</code>.</p>',16)])])}const u=a(s,[["render",i]]);export{m as __pageData,u as default};
